import base64
import uuid
import requests
from datetime import datetime
from xml.sax.saxutils import quoteattr

SAML_TEMPLATE = """
<samlp:AuthnRequest
    xmlns="urn:oasis:names:tc:SAML:2.0:metadata"
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    ID="{id}"
    Version="2.0"
    IssueInstant="{timestamp}"
    Destination="{destination}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" >
    <saml:Issuer xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion">{issuer}</saml:Issuer>
    <samlp:NameIDPolicy
        xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        Format="urn:oasis:names:tc:SAML:2.0:nameid-format:unspecified"
        AllowCreate="true" />
</samlp:AuthnRequest>
""".strip()

def format_saml_request(destination, issuer):
    request = SAML_TEMPLATE.format(
        id= "_{}".format(uuid.uuid4()),
        timestamp= datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ'),
        destination= destination,
        issuer= issuer
    )
    return base64.b64encode(request.encode('utf-8')).decode('utf-8')

def send_saml_request(url, saml_request):
    response = requests.post(url, data={'SAMLRequest': saml_request})
    return response.text

# Usage
formatted_request = format_saml_request('https://idp.example.com', 'https://sp.example.com')
